          <img [src]="item.src" [alt]="item.title" class="aspect-square size-full object-cover" />
        </ng-template>
      </hb-gallery>

      <p class="font-mono text-[12px] text-muted-foreground">
        {{ items[current()].title }} · {{ current() + 1 }}/{{ items.length }}
      </p>
    </div>
